@@ -106,9 +106,9 @@ public class CSRFHandlerImpl implements CSRFHandler {
     return saltPlusToken + "." + signature;
   }

-  private boolean validateToken(String header) {
+  private boolean validateToken(String header, String cookie) {

-    if (header == null) {
